'use client';
import { useToast } from '@/hooks/use-toast';
import { AnimatePresence, motion } from 'framer-motion';
import {
  MapPin,
  Calendar,
  Ticket,
  DollarSign,
  Edit,
  Eye,
  Clock as PendingIcon,
  Plus,
  Download,
  Trash2,
} from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/Card';
import { Button } from '@/components/ui/button';
import { Calendar as CalendarComp } from '@/components/ui/calendar';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { useEffect, useState } from 'react';
import { EventCategory } from '@/types';
import Link from 'next/link';
import { useDebounce } from 'use-debounce';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { useAuth } from '@/context/AuthContext';
import Pagination from '@/components/ui/Pagination';
import { Loading } from '@/components/ui/Loading';
import DeleteConfirmationDialog from '@/components/dialog/DeleteConfirmationDialog';
import { deleteEvent } from '@/api/events';
import SearchInput from '@/components/ui/SearchInput';
import { fetchEvents } from '@/api/events/events';
import { filterLabels } from '@/constants/filters';
import EventCard from '@/components/ui/EventCard';
import { BarChart, DonutChart } from '@/components/ui/Charts';

// تعريفات الحركات
const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1,
      delayChildren: 0.2,
    },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.5,
      ease: 'easeOut',
    },
  },
  hover: {
    scale: 1.02,
    transition: {
      duration: 0.3,
    },
  },
};
const HostDashboard = () => {
  const { token } = useAuth();
  const { toast } = useToast();
  const [flag, setFlag] = useState(false);
  const [events, setEvents] = useState<EventCategory[]>([]);
  const [date, setDate] = useState<Date | undefined>(undefined);
  const [activeFilter, setActiveFilter] = useState<
    'all' | 'upcoming' | 'past' | 'price' | 'pending' | 'approved' | 'rejected'
  >('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);

  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);

  const [currentPage, setCurrentPage] = useState(1); // حالة Pagination الجديدة
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);
  const [eventsPerPage] = useState(6); // عدد الأحداث في كل صفحة

  const [isCalendarOpen, setIsCalendarOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<EventCategory | null>(
    null
  );
  const [loading, setLoading] = useState(false);
  const [downloadingReportPdf, setdownloadingReportPdfPdf] = useState<
    string | null
  >(null);

  // Function to download invoice
  const downloadingReport = async (eventId: string) => {
    if (!token) return;

    setdownloadingReportPdfPdf(eventId);
    try {
      const response = await fetch(
        `http://localhost:8080/reports/event/${eventId}`,
        {
          method: 'GET',
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      if (!response.ok) {
        throw new Error(await response.text());
      }

      // Create blob from response
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);

      // Create download link
      const a = document.createElement('a');
      a.href = url;
      a.download = `Invoice-${eventId}.pdf`;
      document.body.appendChild(a);
      a.click();

      // Cleanup
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      toast({
        title: 'Invoice downloaded',
        description: 'The invoice has been successfully downloaded.',
        className: 'bg-green-500 text-white',
      });
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'Failed to download invoice',
        className: 'bg-red-600 text-white border-0',
      });
    } finally {
      setdownloadingReportPdfPdf(null);
    }
  };

  // تصفية الأحداث
  const currentEvents = events?.filter((event) => {
    const matchesSearch = event.title
      .toLowerCase()
      .includes(debouncedQuery.toLowerCase());
    const matchesFilter =
      activeFilter === 'all' ||
      (activeFilter === 'upcoming' && event.status === 'upcoming') ||
      (activeFilter === 'past' && event.status === 'past') ||
      (activeFilter === 'pending' && event.status === 'pending') ||
      (activeFilter === 'approved' && event.status === 'approved') ||
      (activeFilter === 'rejected' && event.status === 'rejected');

    // Date filter: only apply if a date is selected
    const matchesDate = (() => {
      if (!date) return true;
      const selected = new Date(date);
      selected.setHours(0, 0, 0, 0);

      // Support either single date or range (startDate/endDate)
      if (event.date) {
        const d = new Date(event.date);
        d.setHours(0, 0, 0, 0);
        return d.getTime() === selected.getTime();
      }
      if (event.startDate && event.endDate) {
        const start = new Date(event.startDate);
        const end = new Date(event.endDate);
        start.setHours(0, 0, 0, 0);
        end.setHours(0, 0, 0, 0);
        return selected.getTime() >= start.getTime() && selected.getTime() <= end.getTime();
      }
      return true;
    })();

    return matchesSearch && matchesFilter && matchesDate;
  });

  useEffect(() => {
    fetchEvents({
      token,
      currentPage,
      eventsPerPage,
      activeFilter,
      role: 'host',
      toast,
      setLoading,
    }).then((data) => {
      setEvents(data.events);
      setTotalPages(data.totalPages);
      setTotalItems(data.totalItems);
    });
  }, [currentPage, activeFilter]);

  // إعادة تعيين الصفحة إلى 1 عند تغيير الفلتر
  useEffect(() => {
    setCurrentPage(1);
  }, [activeFilter]);

  // تغيير الصفحة
  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);

  // إحصائيات الأحداث
  const stats = {
    upcomingEvents:
      events?.filter((e) => new Date(e.date) > new Date()).length || 0,
    pendingEvents: events?.filter((e) => e.status === 'pending').length || 0,
  };

  const onDelete = (event: EventCategory) => {
    setSelectedEvent(event);
    setIsDeleteDialogOpen(true);
  };
  const handleDelete = async () => {
    if (!selectedEvent || !token) return;

    await deleteEvent(
      token,
      selectedEvent,
      setEvents,
      setSelectedEvent,
      setIsDeleteDialogOpen,
      toast
    );
  };

  if (loading) {
    return <Loading />;
  }

  return (
    <motion.div
      initial='hidden'
      animate='visible'
      variants={containerVariants}
      className='p-4 md:p-6 space-y-6 max-w-7xl mx-auto'
    >
      {/* Header */}
      <motion.div variants={itemVariants}>
        <Card className='bg-gradient-to-r from-purple-800 to-pink-700 text-white shadow-xl'>
          <div className='p-6'>
            <motion.h2 className='text-2xl md:text-3xl font-bold mb-2'>
              Welcome back, Host!
            </motion.h2>
            <p className='opacity-90 text-purple-100'>
              Here's what's happening with your events today.
            </p>
          </div>
        </Card>
      </motion.div>

      {/* Stats Cards */}
      <motion.div
        className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4'
        variants={containerVariants}
      >
        {[
          {
            title: 'Total Events',
            value: totalItems,
            icon: Ticket,
            trend: '+12%',
          },
          {
            title: 'Upcoming',
            value: stats.upcomingEvents,
            icon: Calendar,
            trend: '+2',
          },
          {
            title: 'Pending',
            value: stats.pendingEvents,
            icon: PendingIcon,
            trend: '+3',
          },
          {
            title: 'Total Revenue',
            icon: DollarSign,
            trend: '+15%',
          },
        ].map((stat, index) => (
          <motion.div
            key={stat.title}
            variants={itemVariants}
          >
            <Card className='hover:shadow-lg transition-shadow h-full'>
              <CardHeader className='flex flex-row items-center justify-between space-y-0 pb-2'>
                <CardTitle className='text-sm font-medium text-gray-500'>
                  {stat.title}
                </CardTitle>
                <stat.icon className='h-5 w-5 text-purple-500' />
              </CardHeader>
              <CardContent>
                <div className='text-2xl font-bold'>{stat.value}</div>
                <p className='text-xs text-muted-foreground'>
                  {stat.trend} from last month
                </p>
              </CardContent>
            </Card>
          </motion.div>
        ))}
      </motion.div>

      {/* Charts */}
      <motion.div className='grid grid-cols-1 lg:grid-cols-3 gap-6' variants={containerVariants}>
        <motion.div variants={itemVariants} className='p-4 rounded-2xl bg-white border border-purple-100 shadow-sm'>
          <h4 className='text-sm font-semibold text-gray-600 mb-3'>Registrations per Category</h4>
          <DonutChart
            data={[
              { label: 'Tech', value: events.filter(e => e.category?.name?.toLowerCase().includes('tech')).length, color: '#8b5cf6' },
              { label: 'Art', value: events.filter(e => e.category?.name?.toLowerCase().includes('art')).length, color: '#ec4899' },
              { label: 'Sports', value: events.filter(e => e.category?.name?.toLowerCase().includes('sport')).length, color: '#22c55e' },
            ]}
          />
        </motion.div>
        <motion.div variants={itemVariants} className='p-4 rounded-2xl bg-white border border-purple-100 shadow-sm lg:col-span-2'>
          <h4 className='text-sm font-semibold text-gray-600 mb-3'>Upcoming vs Past</h4>
          <BarChart
            data={[
              { label: 'Upcoming', value: stats.upcomingEvents, color: '#8b5cf6' },
              { label: 'Pending', value: stats.pendingEvents, color: '#f59e0b' },
              { label: 'Total', value: totalItems, color: '#ec4899' },
            ]}
            height={160}
          />
        </motion.div>
      </motion.div>

      {/* Controls */}
      <motion.div
        className='flex flex-col xl:flex-row gap-3 items-stretch my-10 xl:items-center'
        variants={itemVariants}
      >
        {/* Search Input */}
        <SearchInput
          name='Events'
          searchQuery={searchQuery}
          setSearchQuery={setSearchQuery}
          setCurrentPage={() => setCurrentPage(1)}
        />
        {/* Filters Tabs */}
        <div className='order-3 xl:order-none flex-1 overflow-x-auto'>
          <Tabs
            value={activeFilter}
            onValueChange={(val) => {
              setActiveFilter(val as typeof activeFilter);
              setCurrentPage(1);
            }}
            className='w-full'
          >
            <TabsList className='bg-transparent gap-2 p-1 flex-wrap justify-start w-full'>
              {filterLabels.map(({ label, icon: Icon, value }) => (
                <TabsTrigger
                  value={value || ''}
                  key={value}
                  className='
                    rounded-full px-3 py-1 text-xs md:text-sm md:px-4 md:py-2 whitespace-nowrap
                    bg-gradient-to-r from-purple-50 to-pink-50 text-purple-700 border border-purple-200/60 shadow-sm
                    hover:shadow-md hover:brightness-105 transition-all duration-300
                    data-[state=active]:from-purple-600 data-[state=active]:to-pink-600 data-[state=active]:text-white data-[state=active]:border-transparent
                  '
                >
                  <div className='flex items-center gap-1 md:gap-2'>
                    <Icon className='h-3 w-3 md:h-4 md:w-4' />
                    {label}
                  </div>
                </TabsTrigger>
              ))}
            </TabsList>
          </Tabs>
        </div>

        {/* Calendar Popover */}
        <Popover
          open={isCalendarOpen}
          onOpenChange={setIsCalendarOpen}
        >
          <PopoverTrigger asChild>
            <Button
              variant='outline'
              className='rounded-full gap-2 order-2 xl:order-none'
            >
              <Calendar className='h-4 w-4' />
              <span>{date ? date.toLocaleDateString() : 'Select Date'}</span>
            </Button>
          </PopoverTrigger>
          <PopoverContent
            className='w-auto p-0'
            align='end'
          >
            <CalendarComp
              mode='single'
              selected={date}
              onSelect={(selectedDate) => {
                setDate(selectedDate);
                setIsCalendarOpen(false);
              }}
              initialFocus
            />
          </PopoverContent>
        </Popover>

        {/* Create Event */}
        <Button className='bg-gradient-to-r from-purple-800 to-pink-700 order-4 xl:order-none'>
          <Plus className='text-white'></Plus>
          <Link href='/create'>Create Events</Link>
        </Button>
      </motion.div>

      {/* Events Grid */}
      {currentEvents?.length > 0 ? (
        <>
          <motion.div
            className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6'
            variants={containerVariants}
          >
            <AnimatePresence>
              {currentEvents?.map((event) => (
                <motion.div
                  key={event._id}
                  variants={itemVariants}
                  whileHover='hover'
                  className='relative group'
                >
                  <EventCard
                    event={event}
                    href={`/host/events/${event._id}`}
                    className='transition-all duration-300 group-hover:shadow-xl group-hover:shadow-purple-500/20'
                    role='host'
                    actionsMode='menu'
                    onEdit={() => {
                      window.location.href = `/host/events/${event._id}/edit`;
                    }}
                    onDelete={() => onDelete(event)}
                    onDownloadInvoice={() => downloadingReport(event._id)}
                    footer={
                      <Link
                        href={`/host/events/${event._id}/edit`}
                        className='inline-flex items-center rounded-full bg-white text-purple-700 ring-1 ring-purple-200 px-3 py-1.5 text-xs sm:text-sm font-medium shadow-sm hover:bg-purple-50 active:scale-[0.98] transition-all'
                      >
                        Edit
                      </Link>
                    }
                  />
                </motion.div>
              ))}
            </AnimatePresence>
          </motion.div>
        </>
      ) : (
        <motion.div
          className='text-center py-30 space-y-4'
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
        >
          <div className='text-xl font-bold'>No events found</div>
          <p className='text-muted-foreground'>
            {searchQuery
              ? 'Try a different search term'
              : 'Create your first event to get started'}
          </p>
          {/* Create Event */}
          <Button className='bg-gradient-to-r from-purple-800 to-pink-700'>
            <Plus className='text-white'></Plus>
            <Link href='/create'>Create Events</Link>
          </Button>
        </motion.div>
      )}

      {/* Pagination Controls */}
      {currentEvents.length > 0 && (
        <Pagination
          currentPage={currentPage}
          totalPages={totalPages}
          totalItems={totalItems}
          paginate={paginate}
        />
      )}

      {/* Delete Confirmation Modal */}
      <DeleteConfirmationDialog
        open={isDeleteDialogOpen}
        onClose={() => setIsDeleteDialogOpen(false)}
        title='Delete Event'
        description={`Are you sure you want to delete ${selectedEvent?.title}?`}
        onConfirm={handleDelete}
      />
    </motion.div>
  );
};

export default HostDashboard;